import type { ApiConfig } from "@birthub/config";
import { createLogger } from "@birthub/logger";
import {
  Role,
  prisma,
  type Prisma
} from "@birthub/database";
import Stripe from "stripe";

import { ProblemDetailsError } from "../../lib/problem-details.js";
import { createStripeClient } from "./stripe.client.js";
import {
  findOrganizationByReference,
  type DatabaseClient
} from "./service.shared.js";

const logger = createLogger("billing-service");

type CheckoutLocale = "en" | "es" | "fr" | "it" | "pt-BR";

function normalizeStripeLocale(
  locale: string | null | undefined
): CheckoutLocale | undefined {
  if (!locale) {
    return undefined;
  }

  const normalized = locale.toLowerCase();
  const byPrefix: Record<string, Stripe.Checkout.SessionCreateParams.Locale> = {
    en: "en",
    "en-us": "en",
    es: "es",
    fr: "fr",
    it: "it",
    pt: "pt-BR",
    "pt-br": "pt-BR"
  };

  return byPrefix[normalized] ?? byPrefix[normalized.split("-")[0] ?? ""] ?? undefined;
}

function readOrganizationSetting(
  settings: Prisma.JsonValue | null | undefined,
  key: string
): string | null {
  if (!settings || typeof settings !== "object" || Array.isArray(settings)) {
    return null;
  }

  const value = (settings as Record<string, unknown>)[key];
  return typeof value === "string" && value.trim().length > 0 ? value.trim() : null;
}

export function resolveCheckoutPreferences(input: {
  countryCode?: string | null | undefined;
  locale?: string | null | undefined;
  settings: Prisma.JsonValue | null | undefined;
}): {
  countryCode: string | null;
  locale: CheckoutLocale | undefined;
} {
  const locale =
    normalizeStripeLocale(input.locale) ??
    normalizeStripeLocale(readOrganizationSetting(input.settings, "locale"));
  const countryCode =
    input.countryCode?.trim().toUpperCase() ??
    readOrganizationSetting(input.settings, "countryCode")?.toUpperCase() ??
    null;

  return {
    countryCode,
    locale
  };
}

export async function provisionStripeCustomerForOrganization(input: {
  client?: DatabaseClient;
  config: ApiConfig;
  email: string;
  name: string;
  organizationReference: string;
}): Promise<string> {
  const client = input.client ?? prisma;
  const organization = await findOrganizationByReference(input.organizationReference, client);

  if (!organization) {
    throw new ProblemDetailsError({
      detail: "Organization not found when provisioning Stripe customer.",
      status: 404,
      title: "Not Found"
    });
  }

  if (organization.stripeCustomerId) {
    return organization.stripeCustomerId;
  }

  const stripe = createStripeClient(input.config);
  const customer = await stripe.customers.create({
    email: input.email,
    metadata: {
      organizationId: organization.id,
      tenantId: organization.tenantId
    },
    name: input.name
  });

  await client.organization.update({
    data: {
      stripeCustomerId: customer.id
    },
    where: {
      id: organization.id
    }
  });

  await client.subscription.updateMany({
    data: {
      stripeCustomerId: customer.id
    },
    where: {
      organizationId: organization.id
    }
  });

  logger.info(
    {
      event: "billing.customer.provisioned",
      organizationId: organization.id,
      stripeCustomerId: customer.id,
      tenantId: organization.tenantId
    },
    "Provisioned Stripe customer for organization"
  );

  return customer.id;
}

export async function resolveCustomerForCheckout(input: {
  config: ApiConfig;
  organizationReference: string;
}): Promise<string> {
  const organization = await prisma.organization.findFirst({
    include: {
      memberships: {
        include: {
          user: true
        },
        orderBy: {
          createdAt: "asc"
        },
        take: 1,
        where: {
          role: Role.OWNER
        }
      }
    },
    where: {
      OR: [{ id: input.organizationReference }, { tenantId: input.organizationReference }]
    }
  });

  if (!organization) {
    throw new ProblemDetailsError({
      detail: "Organization not found for checkout.",
      status: 404,
      title: "Not Found"
    });
  }

  if (organization.stripeCustomerId) {
    return organization.stripeCustomerId;
  }

  const owner = organization.memberships[0]?.user;
  const email = owner?.email ?? `billing+${organization.tenantId}@birthub.local`;
  const name = owner?.name ?? organization.name;

  return provisionStripeCustomerForOrganization({
    config: input.config,
    email,
    name,
    organizationReference: organization.id
  });
}

// @ts-nocheck
import type { ApiConfig } from "@birthub/config";
import { Role } from "@birthub/database";
import { Router } from "express";

import { Auditable } from "../../audit/auditable.js";
import {
  RequireRole,
  requireAuthenticatedSession
} from "../../common/guards/index.js";
import { asyncHandler, ProblemDetailsError } from "../../lib/problem-details.js";
import { requireStringValue } from "../../lib/request-values.js";
import { validateBody } from "../../middleware/validate-body.js";
import {
  appointmentQuerySchema,
  clinicalNoteQuerySchema,
  clinicalNoteSchema,
  clinicalNoteUpdateSchema,
  createAppointmentSchema,
  createPatientSchema,
  neonatalRecordSchema,
  patientListQuerySchema,
  pregnancyRecordSchema,
  updateAppointmentSchema,
  updatePatientSchema
} from "./schemas.js";
import { clinicalService } from "./service.js";

function requireClinicalContext(request: {
  context: {
    organizationId: string | null;
    tenantId: string | null;
    userId: string | null;
  };
}) {
  if (!request.context.organizationId || !request.context.tenantId) {
    throw new ProblemDetailsError({
      detail: "A valid tenant-aware authenticated session is required.",
      status: 401,
      title: "Unauthorized"
    });
  }

  return {
    organizationId: request.context.organizationId,
    tenantId: request.context.tenantId,
    userId: request.context.userId
  };
}

export function createClinicalRouter(
  config?: Pick<ApiConfig, "clinicalWorkspaceEnabled">
): Router {
  const router = Router();
  const clinicalWorkspaceEnabled = config?.clinicalWorkspaceEnabled === true;

  router.use((request, _response, next) => {
    if (clinicalWorkspaceEnabled) {
      next();
      return;
    }

    next(
      new ProblemDetailsError({
        detail:
          "The clinical workspace router is disabled because the clinical domain remains outside the active product until schema support is reintroduced.",
        status: 404,
        title: "Not Found"
      })
    );
  });

  router.get(
    "/patients",
    requireAuthenticatedSession,
    asyncHandler(async (request, response) => {
      const filters = patientListQuerySchema.parse(
        request.query
      ) as Parameters<typeof clinicalService.listPatients>[1];
      const payload = await clinicalService.listPatients(requireClinicalContext(request), filters);

      response.status(200).json({
        ...payload,
        requestId: request.context.requestId
      });
    })
  );

  router.post(
    "/patients",
    requireAuthenticatedSession,
    RequireRole(Role.MEMBER),
    validateBody(createPatientSchema),
    asyncHandler(
      Auditable({
        action: "patient.created",
        entityType: "patient",
        requireActor: true,
        resolveEntityId: (_request, _response, result) =>
          typeof result === "object" && result && "patient" in result
            ? String((result as { patient?: { id?: string } }).patient?.id ?? "")
            : undefined
      })(async (request, response) => {
        const payload = await clinicalService.createPatient(
          requireClinicalContext(request),
          createPatientSchema.parse(request.body) as Parameters<typeof clinicalService.createPatient>[1]
        );

        response.status(201).json({
          ...payload,
          requestId: request.context.requestId
        });
        return payload;
      })
    )
  );

  router.get(
    "/patients/:id",
    requireAuthenticatedSession,
    asyncHandler(async (request, response) => {
      const patientId = requireStringValue(request.params.id, "A valid patient id is required.");
      const payload = await clinicalService.getPatientDetail(requireClinicalContext(request), patientId);

      response.status(200).json({
        ...payload,
        requestId: request.context.requestId
      });
    })
  );

  router.patch(
    "/patients/:id",
    requireAuthenticatedSession,
    RequireRole(Role.MEMBER),
    validateBody(updatePatientSchema),
    asyncHandler(
      Auditable({
        action: "patient.updated",
        entityType: "patient",
        requireActor: true,
        resolveEntityId: (request) => request.params.id
      })(async (request, response) => {
        const patientId = requireStringValue(request.params.id, "A valid patient id is required.");
        const payload = await clinicalService.updatePatient(
          requireClinicalContext(request),
          patientId,
          updatePatientSchema.parse(request.body) as Parameters<typeof clinicalService.updatePatient>[2]
        );

        response.status(200).json({
          ...payload,
          requestId: request.context.requestId
        });
        return payload;
      })
    )
  );

  router.delete(
    "/patients/:id",
    requireAuthenticatedSession,
    RequireRole(Role.MEMBER),
    asyncHandler(
      Auditable({
        action: "patient.deleted",
        entityType: "patient",
        requireActor: true,
        resolveEntityId: (request) => request.params.id
      })(async (request, response) => {
        const patientId = requireStringValue(request.params.id, "A valid patient id is required.");
        const payload = await clinicalService.deletePatient(requireClinicalContext(request), patientId);

        response.status(200).json({
          ...payload,
          requestId: request.context.requestId
        });
        return payload;
      })
    )
  );

  router.post(
    "/patients/:id/pregnancy-records",
    requireAuthenticatedSession,
    RequireRole(Role.MEMBER),
    validateBody(pregnancyRecordSchema),
    asyncHandler(
      Auditable({
        action: "patient.pregnancy_record_saved",
        entityType: "pregnancy_record",
        requireActor: true,
        resolveEntityId: (_request, _response, result) =>
          typeof result === "object" && result && "activePregnancy" in result
            ? String((result as { activePregnancy?: { id?: string } | null }).activePregnancy?.id ?? "")
            : undefined
      })(async (request, response) => {
        const patientId = requireStringValue(request.params.id, "A valid patient id is required.");
        const payload = await clinicalService.savePregnancyRecord(requireClinicalContext(request), {
          patientId,
          payload:
            pregnancyRecordSchema.parse(request.body) as Parameters<
              typeof clinicalService.savePregnancyRecord
            >[1]["payload"]
        });

        response.status(200).json({
          ...payload,
          requestId: request.context.requestId
        });
        return payload;
      })
    )
  );

  router.patch(
    "/patients/:id/pregnancy-records/:recordId",
    requireAuthenticatedSession,
    RequireRole(Role.MEMBER),
    validateBody(pregnancyRecordSchema),
    asyncHandler(
      Auditable({
        action: "patient.pregnancy_record_saved",
        entityType: "pregnancy_record",
        requireActor: true,
        resolveEntityId: (request) => request.params.recordId
      })(async (request, response) => {
        const patientId = requireStringValue(request.params.id, "A valid patient id is required.");
        const recordId = requireStringValue(
          request.params.recordId,
          "A valid pregnancy record id is required."
        );
        const payload = await clinicalService.savePregnancyRecord(requireClinicalContext(request), {
          patientId,
          payload:
            pregnancyRecordSchema.parse(request.body) as Parameters<
              typeof clinicalService.savePregnancyRecord
            >[1]["payload"],
          recordId
        });

        response.status(200).json({
          ...payload,
          requestId: request.context.requestId
        });
        return payload;
      })
    )
  );

  router.post(
    "/patients/:id/neonatal-records",
    requireAuthenticatedSession,
    RequireRole(Role.MEMBER),
    validateBody(neonatalRecordSchema),
    asyncHandler(
      Auditable({
        action: "patient.neonatal_record_saved",
        entityType: "neonatal_record",
        requireActor: true
      })(async (request, response) => {
        const patientId = requireStringValue(request.params.id, "A valid patient id is required.");
        const payload = await clinicalService.saveNeonatalRecord(requireClinicalContext(request), {
          patientId,
          payload:
            neonatalRecordSchema.parse(request.body) as Parameters<
              typeof clinicalService.saveNeonatalRecord
            >[1]["payload"]
        });

        response.status(200).json({
          ...payload,
          requestId: request.context.requestId
        });
        return payload;
      })
    )
  );

  router.patch(
    "/patients/:id/neonatal-records/:recordId",
    requireAuthenticatedSession,
    RequireRole(Role.MEMBER),
    validateBody(neonatalRecordSchema),
    asyncHandler(
      Auditable({
        action: "patient.neonatal_record_saved",
        entityType: "neonatal_record",
        requireActor: true,
        resolveEntityId: (request) => request.params.recordId
      })(async (request, response) => {
        const patientId = requireStringValue(request.params.id, "A valid patient id is required.");
        const recordId = requireStringValue(
          request.params.recordId,
          "A valid neonatal record id is required."
        );
        const payload = await clinicalService.saveNeonatalRecord(requireClinicalContext(request), {
          patientId,
          payload:
            neonatalRecordSchema.parse(request.body) as Parameters<
              typeof clinicalService.saveNeonatalRecord
            >[1]["payload"],
          recordId
        });

        response.status(200).json({
          ...payload,
          requestId: request.context.requestId
        });
        return payload;
      })
    )
  );

  router.get(
    "/appointments",
    requireAuthenticatedSession,
    asyncHandler(async (request, response) => {
      const filters = appointmentQuerySchema.parse(request.query);
      const payload = await clinicalService.listAppointments(
        requireClinicalContext(request),
        {
          ...(filters.date ? { anchorDate: filters.date } : {}),
          ...(filters.patientId ? { patientId: filters.patientId } : {}),
          ...(filters.status ? { status: filters.status } : {}),
          view: filters.view
        } as Parameters<typeof clinicalService.listAppointments>[1]
      );

      response.status(200).json({
        ...payload,
        requestId: request.context.requestId
      });
    })
  );

  router.post(
    "/appointments",
    requireAuthenticatedSession,
    RequireRole(Role.MEMBER),
    validateBody(createAppointmentSchema),
    asyncHandler(
      Auditable({
        action: "appointment.created",
        entityType: "appointment",
        requireActor: true,
        resolveEntityId: (_request, _response, result) =>
          typeof result === "object" && result && "appointment" in result
            ? String((result as { appointment?: { id?: string } }).appointment?.id ?? "")
            : undefined
      })(async (request, response) => {
        const payload = await clinicalService.createAppointment(
          requireClinicalContext(request),
          createAppointmentSchema.parse(request.body) as Parameters<
            typeof clinicalService.createAppointment
          >[1]
        );

        response.status(201).json({
          ...payload,
          requestId: request.context.requestId
        });
        return payload;
      })
    )
  );

  router.get(
    "/appointments/:id",
    requireAuthenticatedSession,
    asyncHandler(async (request, response) => {
      const appointmentId = requireStringValue(
        request.params.id,
        "A valid appointment id is required."
      );
      const payload = await clinicalService.getAppointment(
        requireClinicalContext(request),
        appointmentId
      );

      response.status(200).json({
        ...payload,
        requestId: request.context.requestId
      });
    })
  );

  router.patch(
    "/appointments/:id",
    requireAuthenticatedSession,
    RequireRole(Role.MEMBER),
    validateBody(updateAppointmentSchema),
    asyncHandler(
      Auditable({
        action: "appointment.updated",
        entityType: "appointment",
        requireActor: true,
        resolveEntityId: (request) => request.params.id
      })(async (request, response) => {
        const appointmentId = requireStringValue(
          request.params.id,
          "A valid appointment id is required."
        );
        const payload = await clinicalService.updateAppointment(
          requireClinicalContext(request),
          appointmentId,
          updateAppointmentSchema.parse(request.body) as Parameters<
            typeof clinicalService.updateAppointment
          >[2]
        );

        response.status(200).json({
          ...payload,
          requestId: request.context.requestId
        });
        return payload;
      })
    )
  );

  router.delete(
    "/appointments/:id",
    requireAuthenticatedSession,
    RequireRole(Role.MEMBER),
    asyncHandler(
      Auditable({
        action: "appointment.deleted",
        entityType: "appointment",
        requireActor: true,
        resolveEntityId: (request) => request.params.id
      })(async (request, response) => {
        const appointmentId = requireStringValue(
          request.params.id,
          "A valid appointment id is required."
        );
        const payload = await clinicalService.deleteAppointment(
          requireClinicalContext(request),
          appointmentId
        );

        response.status(200).json({
          ...payload,
          requestId: request.context.requestId
        });
        return payload;
      })
    )
  );

  router.get(
    "/clinical-notes",
    requireAuthenticatedSession,
    asyncHandler(async (request, response) => {
      const filters = clinicalNoteQuerySchema.parse(
        request.query
      ) as Parameters<typeof clinicalService.listClinicalNotes>[1];
      const payload = await clinicalService.listClinicalNotes(requireClinicalContext(request), filters);

      response.status(200).json({
        ...payload,
        requestId: request.context.requestId
      });
    })
  );

  router.get(
    "/clinical-notes/:noteGroupId/history",
    requireAuthenticatedSession,
    asyncHandler(async (request, response) => {
      const noteGroupId = requireStringValue(
        request.params.noteGroupId,
        "A valid clinical note group id is required."
      );
      const payload = await clinicalService.getClinicalNoteHistory(
        requireClinicalContext(request),
        noteGroupId
      );

      response.status(200).json({
        ...payload,
        requestId: request.context.requestId
      });
    })
  );

  router.post(
    "/clinical-notes",
    requireAuthenticatedSession,
    RequireRole(Role.MEMBER),
    validateBody(clinicalNoteSchema),
    asyncHandler(
      Auditable({
        action: "clinical_note.created",
        entityType: "clinical_note",
        requireActor: true,
        resolveEntityId: (_request, _response, result) =>
          typeof result === "object" && result && "note" in result
            ? String((result as { note?: { noteGroupId?: string } }).note?.noteGroupId ?? "")
            : undefined
      })(async (request, response) => {
        const payload = await clinicalService.createClinicalNote(
          requireClinicalContext(request),
          clinicalNoteSchema.parse(request.body) as Parameters<typeof clinicalService.createClinicalNote>[1]
        );

        response.status(201).json({
          ...payload,
          requestId: request.context.requestId
        });
        return payload;
      })
    )
  );

  router.patch(
    "/clinical-notes/:noteGroupId",
    requireAuthenticatedSession,
    RequireRole(Role.MEMBER),
    validateBody(clinicalNoteUpdateSchema),
    asyncHandler(
      Auditable({
        action: "clinical_note.versioned",
        entityType: "clinical_note",
        requireActor: true,
        resolveEntityId: (request) => request.params.noteGroupId
      })(async (request, response) => {
        const noteGroupId = requireStringValue(
          request.params.noteGroupId,
          "A valid clinical note group id is required."
        );
        const payload = await clinicalService.updateClinicalNote(
          requireClinicalContext(request),
          noteGroupId,
          clinicalNoteUpdateSchema.parse(request.body) as Parameters<
            typeof clinicalService.updateClinicalNote
          >[2]
        );

        response.status(200).json({
          ...payload,
          requestId: request.context.requestId
        });
        return payload;
      })
    )
  );

  router.delete(
    "/clinical-notes/:noteGroupId",
    requireAuthenticatedSession,
    RequireRole(Role.MEMBER),
    asyncHandler(
      Auditable({
        action: "clinical_note.deleted",
        entityType: "clinical_note",
        requireActor: true,
        resolveEntityId: (request) => request.params.noteGroupId
      })(async (request, response) => {
        const noteGroupId = requireStringValue(
          request.params.noteGroupId,
          "A valid clinical note group id is required."
        );
        const payload = await clinicalService.deleteClinicalNote(
          requireClinicalContext(request),
          noteGroupId
        );

        response.status(200).json({
          ...payload,
          requestId: request.context.requestId
        });
        return payload;
      })
    )
  );

  return router;
}

import {
  prisma,
  withTenantDatabaseContext
} from "@birthub/database";

import {
  APPOINTMENT_STATUS,
  CLINICAL_PATIENT_LIST_PAGE_LIMIT,
  NEONATAL_OUTCOME,
  PATIENT_STATUS,
  PREGNANCY_OUTCOME,
  PREGNANCY_STATUS,
  assertFound,
  deriveClinicalAlerts,
  findNextAppointment,
  normalizeOptionalString,
  normalizeStringArray,
  parseOptionalDate,
  parseRequiredDate,
  resolvePageLimit,
  serializeAppointment,
  serializePatient,
  serializePregnancyRecord,
  type ClinicalContext,
  type NeonatalOutcome,
  type NeonatalSex,
  type PatientStatus,
  type PregnancyOutcome,
  type PregnancyRiskLevel,
  type PregnancyStatus
} from "./service-support.js";
import {
  asClinicalTransaction,
  buildAppointmentSelect,
  buildClinicalNoteSelect,
  buildPatientSelect,
  buildPatientWhere,
  buildPregnancyMutation,
  buildPregnancySelect,
  ensureClinicalRuntimeAvailable,
  findActivePregnancy,
  getPatientDetailInternal,
  type PatientListRecord
} from "./service-runtime.js";

type PregnancyRecordPayload = {
  abortions?: number;
  complications?: string[];
  estimatedDeliveryDate?: string | null;
  fetalCount?: number;
  gravidity?: number;
  lastMenstrualPeriod?: string | null;
  notes?: string | null;
  outcome?: PregnancyOutcome | null;
  outcomeDate?: string | null;
  parity?: number;
  previousCesareans?: number;
  riskLevel?: PregnancyRiskLevel;
  status?: PregnancyStatus;
};

type CreatePatientPayload = {
  allergies?: string[];
  birthDate?: string | null;
  bloodType?: string | null;
  chronicConditions?: string[];
  documentId?: string | null;
  email?: string | null;
  fullName: string;
  medicalRecordNumber?: string | null;
  notes?: string | null;
  phone?: string | null;
  preferredName?: string | null;
  pregnancyRecord?: PregnancyRecordPayload;
  status?: PatientStatus;
};

type UpdatePatientPayload = {
  allergies?: string[];
  birthDate?: string | null;
  bloodType?: string | null;
  chronicConditions?: string[];
  documentId?: string | null;
  email?: string | null;
  fullName?: string;
  medicalRecordNumber?: string | null;
  notes?: string | null;
  phone?: string | null;
  preferredName?: string | null;
  status?: PatientStatus;
};

type SavePregnancyRecordInput = {
  patientId: string;
  payload: PregnancyRecordPayload;
  recordId?: string;
};

type SaveNeonatalRecordInput = {
  patientId: string;
  payload: {
    apgar1?: number;
    apgar5?: number;
    birthLengthCm?: number;
    birthWeightGrams?: number;
    bornAt: string;
    headCircumferenceCm?: number;
    newbornName?: string | null;
    notes?: string | null;
    outcome?: NeonatalOutcome;
    pregnancyRecordId?: string | null;
    sex?: NeonatalSex | null;
  };
  recordId?: string;
};

export function createPatientMethods() {
  const getPatientDetail = async (context: ClinicalContext, patientId: string) => {
    ensureClinicalRuntimeAvailable();

    return withTenantDatabaseContext(
      async (tx) => getPatientDetailInternal(tx, context, patientId),
      prisma
    );
  };

  const createPatient = async (
    context: ClinicalContext,
    payload: CreatePatientPayload
  ) => {
    ensureClinicalRuntimeAvailable();

    const patientId = await withTenantDatabaseContext(async (tx) => {
      const clinicalTx = asClinicalTransaction(tx);
      const patient = await clinicalTx.patient.create<{ id: string }>({
        data: {
          allergies: normalizeStringArray(payload.allergies),
          birthDate: parseOptionalDate(payload.birthDate),
          bloodType: normalizeOptionalString(payload.bloodType),
          chronicConditions: normalizeStringArray(payload.chronicConditions),
          documentId: normalizeOptionalString(payload.documentId),
          email: normalizeOptionalString(payload.email),
          fullName: payload.fullName.trim(),
          medicalRecordNumber: normalizeOptionalString(payload.medicalRecordNumber),
          notes: normalizeOptionalString(payload.notes),
          organizationId: context.organizationId,
          phone: normalizeOptionalString(payload.phone),
          preferredName: normalizeOptionalString(payload.preferredName),
          status: payload.status ?? PATIENT_STATUS.ACTIVE,
          tenantId: context.tenantId
        },
        select: {
          id: true
        }
      });

      if (payload.pregnancyRecord) {
        await clinicalTx.pregnancyRecord.create({
          data: {
            ...buildPregnancyMutation(payload.pregnancyRecord),
            organizationId: context.organizationId,
            patientId: patient.id,
            tenantId: context.tenantId
          }
        });
      }

      return patient.id;
    }, prisma);

    return getPatientDetail(context, patientId);
  };

  const listPatients = async (
    context: ClinicalContext,
    filters: {
      limit?: number;
      riskLevel?: PregnancyRiskLevel;
      search?: string;
      status?: PatientStatus;
    }
  ) => {
    ensureClinicalRuntimeAvailable();

    return withTenantDatabaseContext(async (tx) => {
      const clinicalTx = asClinicalTransaction(tx);
      const patientPageLimit = resolvePageLimit(
        filters.limit,
        CLINICAL_PATIENT_LIST_PAGE_LIMIT
      );
      const patients = await clinicalTx.patient.findMany<PatientListRecord>({
        include: {
          appointments: {
            orderBy: {
              scheduledAt: "desc"
            },
            select: buildAppointmentSelect(false),
            take: 8,
            where: {
              deletedAt: null,
              tenantId: context.tenantId
            }
          },
          clinicalNotes: {
            orderBy: {
              updatedAt: "desc"
            },
            select: buildClinicalNoteSelect(),
            take: 1,
            where: {
              deletedAt: null,
              isLatest: true,
              tenantId: context.tenantId
            }
          },
          pregnancyRecords: {
            orderBy: [{ estimatedDeliveryDate: "asc" }, { createdAt: "desc" }],
            select: buildPregnancySelect(),
            take: 3,
            where: {
              deletedAt: null,
              tenantId: context.tenantId
            }
          },
          ...buildPatientSelect()
        },
        orderBy: [{ createdAt: "desc" }, { fullName: "asc" }],
        take: patientPageLimit,
        where: buildPatientWhere({
          organizationId: context.organizationId,
          riskLevel: filters.riskLevel,
          search: filters.search,
          status: filters.status,
          tenantId: context.tenantId
        })
      });

      return {
        items: patients.map((patient) => {
          const activePregnancy =
            patient.pregnancyRecords.find(
              (record) => record.status === PREGNANCY_STATUS.ACTIVE
            ) ?? null;
          const nextAppointment = findNextAppointment(patient.appointments);
          const latestAppointment = patient.appointments[0] ?? null;
          const latestClinicalNote = patient.clinicalNotes[0] ?? null;
          const alerts = deriveClinicalAlerts({
            activePregnancy,
            latestAppointment,
            latestClinicalNote,
            nextAppointment
          });

          return {
            activePregnancy: activePregnancy
              ? serializePregnancyRecord(activePregnancy)
              : null,
            alertCount: alerts.length,
            nextAppointment: nextAppointment
              ? serializeAppointment(nextAppointment)
              : null,
            patient: serializePatient(patient)
          };
        }),
        pageSize: patientPageLimit
      };
    }, prisma);
  };

  const updatePatient = async (
    context: ClinicalContext,
    patientId: string,
    payload: UpdatePatientPayload
  ) => {
    ensureClinicalRuntimeAvailable();

    await withTenantDatabaseContext(async (tx) => {
      const clinicalTx = asClinicalTransaction(tx);
      assertFound(
        await clinicalTx.patient.findFirst<{ id: string }>({
          select: {
            id: true
          },
          where: {
            deletedAt: null,
            id: patientId,
            organizationId: context.organizationId,
            tenantId: context.tenantId
          }
        }),
        "Patient was not found for update."
      );

      await clinicalTx.patient.updateMany({
        data: {
          ...(payload.fullName ? { fullName: payload.fullName.trim() } : {}),
          ...(payload.status ? { status: payload.status } : {}),
          ...(payload.birthDate !== undefined
            ? { birthDate: parseOptionalDate(payload.birthDate) }
            : {}),
          ...(payload.bloodType !== undefined
            ? { bloodType: normalizeOptionalString(payload.bloodType) }
            : {}),
          ...(payload.documentId !== undefined
            ? { documentId: normalizeOptionalString(payload.documentId) }
            : {}),
          ...(payload.email !== undefined
            ? { email: normalizeOptionalString(payload.email) }
            : {}),
          ...(payload.medicalRecordNumber !== undefined
            ? {
                medicalRecordNumber: normalizeOptionalString(
                  payload.medicalRecordNumber
                )
              }
            : {}),
          ...(payload.notes !== undefined
            ? { notes: normalizeOptionalString(payload.notes) }
            : {}),
          ...(payload.phone !== undefined
            ? { phone: normalizeOptionalString(payload.phone) }
            : {}),
          ...(payload.preferredName !== undefined
            ? { preferredName: normalizeOptionalString(payload.preferredName) }
            : {}),
          ...(payload.allergies !== undefined
            ? { allergies: normalizeStringArray(payload.allergies) }
            : {}),
          ...(payload.chronicConditions !== undefined
            ? { chronicConditions: normalizeStringArray(payload.chronicConditions) }
            : {})
        },
        where: {
          deletedAt: null,
          id: patientId,
          organizationId: context.organizationId,
          tenantId: context.tenantId
        }
      });
    }, prisma);

    return getPatientDetail(context, patientId);
  };

  const deletePatient = async (context: ClinicalContext, patientId: string) => {
    ensureClinicalRuntimeAvailable();

    const deletedAt = new Date();

    return withTenantDatabaseContext(async (tx) => {
      const clinicalTx = asClinicalTransaction(tx);
      assertFound(
        await clinicalTx.patient.findFirst<{ id: string }>({
          select: {
            id: true
          },
          where: {
            deletedAt: null,
            id: patientId,
            organizationId: context.organizationId,
            tenantId: context.tenantId
          }
        }),
        "Patient was not found for deletion."
      );

      await Promise.all([
        clinicalTx.patient.updateMany({
          data: {
            deletedAt,
            status: PATIENT_STATUS.ARCHIVED
          },
          where: {
            deletedAt: null,
            id: patientId,
            organizationId: context.organizationId,
            tenantId: context.tenantId
          }
        }),
        clinicalTx.pregnancyRecord.updateMany({
          data: {
            deletedAt,
            status: PREGNANCY_STATUS.CLOSED
          },
          where: {
            deletedAt: null,
            organizationId: context.organizationId,
            patientId,
            tenantId: context.tenantId
          }
        }),
        clinicalTx.appointment.updateMany({
          data: {
            deletedAt,
            status: APPOINTMENT_STATUS.CANCELLED
          },
          where: {
            deletedAt: null,
            organizationId: context.organizationId,
            patientId,
            tenantId: context.tenantId
          }
        }),
        clinicalTx.clinicalNote.updateMany({
          data: {
            deletedAt,
            isLatest: false,
            supersededAt: deletedAt
          },
          where: {
            deletedAt: null,
            organizationId: context.organizationId,
            patientId,
            tenantId: context.tenantId
          }
        }),
        clinicalTx.neonatalRecord.updateMany({
          data: {
            deletedAt
          },
          where: {
            deletedAt: null,
            organizationId: context.organizationId,
            patientId,
            tenantId: context.tenantId
          }
        })
      ]);

      return {
        deleted: true,
        patientId
      };
    }, prisma);
  };

  const savePregnancyRecord = async (
    context: ClinicalContext,
    input: SavePregnancyRecordInput
  ) => {
    ensureClinicalRuntimeAvailable();

    await withTenantDatabaseContext(async (tx) => {
      const clinicalTx = asClinicalTransaction(tx);
      assertFound(
        await clinicalTx.patient.findFirst<{ id: string }>({
          select: {
            id: true
          },
          where: {
            deletedAt: null,
            id: input.patientId,
            organizationId: context.organizationId,
            tenantId: context.tenantId
          }
        }),
        "Patient was not found for pregnancy save."
      );

      if (input.recordId) {
        assertFound(
          await clinicalTx.pregnancyRecord.findFirst<{ id: string }>({
            select: {
              id: true
            },
            where: {
              deletedAt: null,
              id: input.recordId,
              organizationId: context.organizationId,
              patientId: input.patientId,
              tenantId: context.tenantId
            }
          }),
          "Pregnancy record was not found."
        );

        if (input.payload.status === PREGNANCY_STATUS.ACTIVE) {
          await clinicalTx.pregnancyRecord.updateMany({
            data: {
              status: PREGNANCY_STATUS.CLOSED
            },
            where: {
              deletedAt: null,
              id: {
                not: input.recordId
              },
              organizationId: context.organizationId,
              patientId: input.patientId,
              status: PREGNANCY_STATUS.ACTIVE,
              tenantId: context.tenantId
            }
          });
        }

        await clinicalTx.pregnancyRecord.updateMany({
          data: buildPregnancyMutation(input.payload),
          where: {
            deletedAt: null,
            id: input.recordId,
            organizationId: context.organizationId,
            patientId: input.patientId,
            tenantId: context.tenantId
          }
        });
      } else {
        if (
          (input.payload.status ?? PREGNANCY_STATUS.ACTIVE) ===
          PREGNANCY_STATUS.ACTIVE
        ) {
          await clinicalTx.pregnancyRecord.updateMany({
            data: {
              status: PREGNANCY_STATUS.CLOSED
            },
            where: {
              deletedAt: null,
              organizationId: context.organizationId,
              patientId: input.patientId,
              status: PREGNANCY_STATUS.ACTIVE,
              tenantId: context.tenantId
            }
          });
        }

        await clinicalTx.pregnancyRecord.create({
          data: {
            ...buildPregnancyMutation(input.payload),
            organizationId: context.organizationId,
            patientId: input.patientId,
            status: input.payload.status ?? PREGNANCY_STATUS.ACTIVE,
            tenantId: context.tenantId
          }
        });
      }
    }, prisma);

    return getPatientDetail(context, input.patientId);
  };

  const saveNeonatalRecord = async (
    context: ClinicalContext,
    input: SaveNeonatalRecordInput
  ) => {
    ensureClinicalRuntimeAvailable();

    await withTenantDatabaseContext(async (tx) => {
      const clinicalTx = asClinicalTransaction(tx);
      assertFound(
        await clinicalTx.patient.findFirst<{ id: string }>({
          select: {
            id: true
          },
          where: {
            deletedAt: null,
            id: input.patientId,
            organizationId: context.organizationId,
            tenantId: context.tenantId
          }
        }),
        "Patient was not found for neonatal save."
      );

      const activePregnancy = await findActivePregnancy(tx, context, input.patientId);
      const pregnancyRecordId =
        normalizeOptionalString(input.payload.pregnancyRecordId) ??
        activePregnancy?.id ??
        null;

      const neonatalData = {
        ...(input.payload.apgar1 !== undefined
          ? { apgar1: input.payload.apgar1 }
          : {}),
        ...(input.payload.apgar5 !== undefined
          ? { apgar5: input.payload.apgar5 }
          : {}),
        ...(input.payload.birthLengthCm !== undefined
          ? { birthLengthCm: input.payload.birthLengthCm }
          : {}),
        ...(input.payload.birthWeightGrams !== undefined
          ? { birthWeightGrams: input.payload.birthWeightGrams }
          : {}),
        ...(input.payload.headCircumferenceCm !== undefined
          ? { headCircumferenceCm: input.payload.headCircumferenceCm }
          : {}),
        ...(input.payload.outcome !== undefined
          ? { outcome: input.payload.outcome }
          : {}),
        ...(input.payload.sex !== undefined ? { sex: input.payload.sex } : {}),
        bornAt: parseRequiredDate(input.payload.bornAt, "bornAt"),
        newbornName: normalizeOptionalString(input.payload.newbornName),
        notes: normalizeOptionalString(input.payload.notes),
        pregnancyRecordId
      };

      if (input.recordId) {
        assertFound(
          await clinicalTx.neonatalRecord.findFirst<{ id: string }>({
            select: {
              id: true
            },
            where: {
              deletedAt: null,
              id: input.recordId,
              organizationId: context.organizationId,
              patientId: input.patientId,
              tenantId: context.tenantId
            }
          }),
          "Neonatal record was not found."
        );

        await clinicalTx.neonatalRecord.updateMany({
          data: neonatalData,
          where: {
            deletedAt: null,
            id: input.recordId,
            organizationId: context.organizationId,
            patientId: input.patientId,
            tenantId: context.tenantId
          }
        });
      } else {
        await clinicalTx.neonatalRecord.create({
          data: {
            ...neonatalData,
            organizationId: context.organizationId,
            patientId: input.patientId,
            tenantId: context.tenantId
          }
        });
      }

      if (pregnancyRecordId) {
        await clinicalTx.pregnancyRecord.updateMany({
          data: {
            outcome:
              (input.payload.outcome ?? NEONATAL_OUTCOME.ALIVE) ===
              NEONATAL_OUTCOME.STILLBIRTH
                ? PREGNANCY_OUTCOME.STILLBIRTH
                : PREGNANCY_OUTCOME.LIVE_BIRTH,
            outcomeDate: parseRequiredDate(input.payload.bornAt, "bornAt"),
            status: PREGNANCY_STATUS.DELIVERED
          },
          where: {
            deletedAt: null,
            id: pregnancyRecordId,
            organizationId: context.organizationId,
            patientId: input.patientId,
            tenantId: context.tenantId
          }
        });
      }
    }, prisma);

    return getPatientDetail(context, input.patientId);
  };

  return {
    createPatient,
    listPatients,
    getPatientDetail,
    updatePatient,
    deletePatient,
    savePregnancyRecord,
    saveNeonatalRecord
  };
}

import {
