async function ensureDefaultPolicies(input: {
  organizationId: string;
  tenantId: string;
}) {
  const retentionPolicyModel = readRetentionModel<RetentionPolicyDelegate>("dataRetentionPolicy");
  await prisma.$transaction(
    DEFAULT_RETENTION_POLICIES.map((policy) =>
      retentionPolicyModel.upsert({
        create: {
          action: policy.action,
          dataCategory: policy.dataCategory,
          legalBasis: policy.legalBasis,
          organizationId: input.organizationId,
          retentionDays: policy.retentionDays,
          tenantId: input.tenantId
        },
        update: {},
        where: {
          organizationId_dataCategory: {
            dataCategory: policy.dataCategory,
            organizationId: input.organizationId
          }
        }
      })
    )
  );
}

async function resolveOrganization(input: { organizationReference: string }) {
  const organization = await findOrganizationByReference(input.organizationReference);

  if (!organization) {
    throw new ProblemDetailsError({
      detail: "Organization not found for retention policy.",
      status: 404,
      title: "Not Found"
    });
  }

  await ensureDefaultPolicies({
    organizationId: organization.id,
    tenantId: organization.tenantId
  });

  return organization;
}

async function executePolicy(input: {
  config: ApiConfig;
  mode: RetentionExecutionMode;
  organizationId: string;
  policy: {
    action: RetentionAction;
    dataCategory: RetentionDataCategory;
    id: string;
    retentionDays: number;
  };
  tenantId: string;
}) {
  const retentionExecutionModel = readRetentionModel<RetentionExecutionDelegate>("dataRetentionExecution");
  const cutoff = new Date(Date.now() - input.policy.retentionDays * 24 * 60 * 60 * 1000);
  let affectedCount = 0;
  let scannedCount = 0;

  switch (input.policy.dataCategory) {
    case RETENTION_DATA_CATEGORY.OUTPUT_ARTIFACTS: {
      const where = {
        createdAt: {
          lt: cutoff
        },
        organizationId: input.organizationId
      };
      scannedCount = await prisma.outputArtifact.count({ where });

      if (input.mode !== RETENTION_EXECUTION_MODE.DRY_RUN && scannedCount > 0) {
        const result = await prisma.outputArtifact.updateMany({
          data: {
            content: REDACTED_OUTPUT_CONTENT,
            contentHash: redactedContentHash()
          },
          where
        });
        affectedCount = result.count;
      }
      break;
    }
    case RETENTION_DATA_CATEGORY.LOGIN_ALERTS: {
      const where = {
        createdAt: {
          lt: cutoff
        },
        organizationId: input.organizationId
      };
      scannedCount = await prisma.loginAlert.count({ where });

      if (input.mode !== RETENTION_EXECUTION_MODE.DRY_RUN && scannedCount > 0) {
        const result = await prisma.loginAlert.deleteMany({ where });
        affectedCount = result.count;
      }
      break;
    }
    case RETENTION_DATA_CATEGORY.MFA_CHALLENGES: {
      const where = {
        createdAt: {
          lt: cutoff
        },
        organizationId: input.organizationId
      };
      scannedCount = await prisma.mfaChallenge.count({ where });

      if (input.mode !== RETENTION_EXECUTION_MODE.DRY_RUN && scannedCount > 0) {
        const result = await prisma.mfaChallenge.deleteMany({ where });
        affectedCount = result.count;
      }
      break;
    }
    case RETENTION_DATA_CATEGORY.MFA_RECOVERY_CODES: {
      const where = {
        OR: [
          {
            createdAt: {
              lt: cutoff
            }
          },
          {
            usedAt: {
              lt: cutoff
            }
          }
        ],
        tenantId: input.tenantId
      };
      scannedCount = await prisma.mfaRecoveryCode.count({ where });

      if (input.mode !== RETENTION_EXECUTION_MODE.DRY_RUN && scannedCount > 0) {
        const result = await prisma.mfaRecoveryCode.deleteMany({ where });
        affectedCount = result.count;
      }
      break;
    }
    case RETENTION_DATA_CATEGORY.SUSPENDED_USERS: {
      const users = await listSuspendedUsersForRetention({
        organizationId: input.organizationId,
        cutoff
      });
      scannedCount = users.length;

      if (input.mode !== RETENTION_EXECUTION_MODE.DRY_RUN && users.length > 0) {
        await Promise.all(
          users.map(async (user) => {
            await prisma.user.update({
              data: {
                email: anonymizedEmail(user.id),
                mfaEnabled: false,
                mfaFailedAttempts: 0,
                mfaLockedUntil: null,
                mfaSecret: null,
                name: "Deleted User",
                passwordHash: await hashPassword(randomToken(18), {
                  memoryKiB: input.config.AUTH_ARGON2_MEMORY_KIB,
                  parallelism: input.config.AUTH_ARGON2_PARALLELISM,
                  passes: input.config.AUTH_ARGON2_PASSES
                })
              },
              where: {
                id: user.id
              }
            });
          })
        );
        affectedCount = users.length;
      }
      break;
    }
    default:
      break;
  }

  const execution = await retentionExecutionModel.create({
    data: {
      action: input.policy.action,
      dataCategory: input.policy.dataCategory,
      mode: input.mode,
      organizationId: input.organizationId,
      policyId: input.policy.id,
      scannedCount,
      affectedCount,
      tenantId: input.tenantId
    }
  });

  await prisma.auditLog.create({
    data: {
      action: "privacy.retention.executed",
      diff: {
        after: {
          action: input.policy.action,
          affectedCount,
          dataCategory: input.policy.dataCategory,
          mode: input.mode,
          scannedCount
        },
        before: {}
      },
      entityId: execution.id,
      entityType: "data_retention_execution",
      tenantId: input.tenantId
    }
  });

  return {
    affectedCount,
    dataCategory: input.policy.dataCategory,
    executionId: execution.id,
    scannedCount
  };
}

export async function listRetentionPolicies(input: {
  organizationReference: string;
}) {
  const retentionExecutionModel = readRetentionModel<RetentionExecutionDelegate>("dataRetentionExecution");
  const organization = await resolveOrganization({
    organizationReference: input.organizationReference
  });

  const [items, executions] = await Promise.all([
    listRetentionPoliciesForOrganization({
      organizationId: organization.id
    }),
    retentionExecutionModel.findMany({
      orderBy: {
        createdAt: "desc"
      },
      take: 20,
      where: {
        organizationId: organization.id
      }
    })
  ]);

  return {
    executions,
    items
  };
}

export async function updateRetentionPolicies(input: {
  organizationReference: string;
  policies: Array<{
    action?: RetentionAction;
    dataCategory: RetentionDataCategory;
    enabled?: boolean;
    retentionDays?: number;
  }>;
}) {
  const organization = await resolveOrganization({
    organizationReference: input.organizationReference
  });

  await prisma.$transaction(
    input.policies.map((policy) =>
      readRetentionModel<RetentionPolicyDelegate>("dataRetentionPolicy").update({
        data: {
          ...(policy.action !== undefined ? { action: policy.action } : {}),
          ...(policy.enabled !== undefined ? { enabled: policy.enabled } : {}),
          ...(policy.retentionDays !== undefined
            ? { retentionDays: policy.retentionDays }
            : {})
        },
        where: {
          organizationId_dataCategory: {
            dataCategory: policy.dataCategory,
            organizationId: organization.id
          }
        }
      })
    )
  );

  return listRetentionPolicies({
    organizationReference: organization.id
  });
}

export async function runRetentionSweep(input: {
  config: ApiConfig;
  mode: RetentionExecutionMode;
  organizationReference?: string;
}) {
  const organizations = input.organizationReference
    ? [await resolveOrganization({ organizationReference: input.organizationReference })]
    : await listOrganizationsForRetentionSweep();

  const results = [];

  for (const organization of organizations) {
    await ensureDefaultPolicies({
      organizationId: organization.id,
      tenantId: organization.tenantId
    });

    const policies = await listRetentionPoliciesForOrganization({
      enabled: true,
      organizationId: organization.id
    });

    for (const policy of policies) {
      results.push(
        await executePolicy({
          config: input.config,
          mode: input.mode,
          organizationId: organization.id,
          policy,
          tenantId: organization.tenantId
        })
      );
    }
  }

  return results;
}

// @ts-nocheck
import { createHmac } from "node:crypto";

import type { ApiConfig } from "@birthub/config";
import { Role, WorkflowTriggerType } from "@birthub/database";
import { lintWorkflowSteps, workflowCanvasSchema } from "@birthub/workflows-core";
import type { Request, Response } from "express";
import { Router } from "express";

import {
  RequireRole,
  requireAuthenticatedSession
} from "../../common/guards/index.js";
import { asyncHandler, ProblemDetailsError } from "../../lib/problem-details.js";
import { validateBody } from "../../middleware/validate-body.js";
import { emitWorkflowInternalEvent } from "../webhooks/eventBus.js";
import {
  workflowCreateSchema,
  workflowRevertSchema,
  workflowRunSchema,
  workflowUpdateSchema
} from "./schemas.js";
import {
  archiveWorkflow,
  createWorkflow,
  getWorkflowById,
  getWorkflowRevisions,
  listWorkflowExecutionLineage,
  listWorkflows,
  revertWorkflow,
  runWorkflowNow,
  updateWorkflow
} from "./service.js";

type WorkflowRouteRegistrar = (router: Router, config: ApiConfig) => void;

function requireTenantId(request: Request): string {
  const tenantId = request.context.tenantId;
  if (!tenantId) {
    throw new ProblemDetailsError({
      detail: "Tenant context is required.",
      status: 401,
      title: "Unauthorized"
    });
  }

  return tenantId;
}

function readWorkflowId(request: Request): string {
  return String(request.params.id ?? "");
}

function withStepLint<T extends { definition: unknown }>(workflow: T): T & {
  stepLint: ReturnType<typeof lintWorkflowSteps> | null;
} {
  const parsed = workflowCanvasSchema.safeParse(workflow.definition);
  if (!parsed.success) {
    return {
      ...workflow,
      stepLint: null
    };
  }

  return {
    ...workflow,
    stepLint: lintWorkflowSteps(parsed.data)
  };
}

function respondWithWorkflow(
  response: Response,
  requestId: string,
  workflow: ({ definition: unknown } & Record<string, unknown>) | null,
  status = 200
) {
  if (!workflow) {
    throw new ProblemDetailsError({
      detail: "Workflow not found.",
      status: 404,
      title: "Not Found"
    });
  }

  response.status(status).json({
    requestId,
    workflow: withStepLint(workflow)
  });
}

function registerListWorkflowsRoute(router: Router): void {
  router.get(
    "/api/v1/workflows",
    requireAuthenticatedSession,
    asyncHandler(async (request, response) => {
      const tenantId = requireTenantId(request);
      const items = await listWorkflows(tenantId);

      response.status(200).json({
        items: items.map((item) => withStepLint(item)),
        requestId: request.context.requestId
      });
    })
  );
}

function registerCreateWorkflowRoute(router: Router, config: ApiConfig): void {
  router.post(
    "/api/v1/workflows",
    requireAuthenticatedSession,
    RequireRole(Role.ADMIN),
    validateBody(workflowCreateSchema),
    asyncHandler(async (request, response) => {
      const tenantId = requireTenantId(request);
      const payload = workflowCreateSchema.parse(request.body);
      const workflow = await createWorkflow(config, tenantId, payload);

      if (!workflow) {
        throw new ProblemDetailsError({
          detail: "Workflow not found after creation.",
          status: 500,
          title: "Internal Server Error"
        });
      }

      respondWithWorkflow(response, request.context.requestId, workflow, 201);
    })
  );
}

function registerWorkflowLineageRoute(router: Router): void {
  router.get(
    "/api/v1/workflows/:id/executions/lineage",
    requireAuthenticatedSession,
    RequireRole(Role.ADMIN),
    asyncHandler(async (request, response) => {
      const tenantId = requireTenantId(request);
      const workflowId = readWorkflowId(request);
      const lineage = await listWorkflowExecutionLineage(workflowId, tenantId);

      response.status(200).json({
        lineage,
        requestId: request.context.requestId,
        workflowId
      });
    })
  );
}

function registerGetWorkflowRoute(router: Router): void {
  router.get(
    "/api/v1/workflows/:id",
    requireAuthenticatedSession,
    asyncHandler(async (request, response) => {
      const tenantId = requireTenantId(request);
      const workflow = await getWorkflowById(readWorkflowId(request), tenantId);

      if (!workflow) {
        throw new ProblemDetailsError({
          detail: "Workflow not found.",
          status: 404,
          title: "Not Found"
        });
      }

      respondWithWorkflow(response, request.context.requestId, workflow);
    })
  );
}

function registerUpdateWorkflowRoute(router: Router, config: ApiConfig): void {
  router.put(
    "/api/v1/workflows/:id",
    requireAuthenticatedSession,
    RequireRole(Role.ADMIN),
    validateBody(workflowUpdateSchema),
    asyncHandler(async (request, response) => {
      const tenantId = requireTenantId(request);
      const workflow = await updateWorkflow(
        config,
        readWorkflowId(request),
        tenantId,
        workflowUpdateSchema.parse(request.body)
      );

      if (!workflow) {
        throw new ProblemDetailsError({
          detail: "Workflow not found after update.",
          status: 404,
          title: "Not Found"
        });
      }

      respondWithWorkflow(response, request.context.requestId, workflow);
    })
  );
}

function registerDeleteWorkflowRoute(router: Router): void {
  router.delete(
    "/api/v1/workflows/:id",
    requireAuthenticatedSession,
    RequireRole(Role.ADMIN),
    asyncHandler(async (request, response) => {
      const tenantId = requireTenantId(request);
      await archiveWorkflow(readWorkflowId(request), tenantId);
      response.status(204).send();
    })
  );
}

function registerWorkflowRevisionRoutes(router: Router, config: ApiConfig): void {
  router.get(
    "/api/v1/workflows/:id/revisions",
    requireAuthenticatedSession,
    RequireRole(Role.ADMIN),
    asyncHandler(async (request, response) => {
      const tenantId = requireTenantId(request);
      const workflowId = readWorkflowId(request);
      const items = await getWorkflowRevisions(workflowId, tenantId);

      response.status(200).json({
        items,
        requestId: request.context.requestId,
        workflowId
      });
    })
  );

  router.post(
    "/api/v1/workflows/:id/revert",
    requireAuthenticatedSession,
    RequireRole(Role.ADMIN),
    validateBody(workflowRevertSchema),
    asyncHandler(async (request, response) => {
      const tenantId = requireTenantId(request);
      const workflowId = readWorkflowId(request);
      const workflow = await revertWorkflow(
        config,
        workflowId,
        tenantId,
        workflowRevertSchema.parse(request.body)
      );

      respondWithWorkflow(response, request.context.requestId, workflow);
    })
  );
}

function registerRunWorkflowRoute(router: Router, config: ApiConfig): void {
  router.post(
    "/api/v1/workflows/:id/run",
    requireAuthenticatedSession,
    RequireRole(Role.ADMIN),
    validateBody(workflowRunSchema),
    asyncHandler(async (request, response) => {
      const tenantId = requireTenantId(request);

      try {
        const result = await runWorkflowNow(
          config,
          readWorkflowId(request),
          tenantId,
          workflowRunSchema.parse(request.body),
          WorkflowTriggerType.MANUAL
        );

        response.status(result.mode === "async" ? 202 : 200).json({
          requestId: request.context.requestId,
          ...result
        });
      } catch (error) {
        if (error instanceof Error && error.message === "WORKFLOW_NOT_PUBLISHED") {
          throw new ProblemDetailsError({
            detail: "Only published workflows can be executed.",
            status: 409,
            title: "Conflict"
          });
        }

        throw error;
      }
    })
  );
}

function buildWebhookUrl(request: Request, workflowId: string): string {
  const host = request.header("x-forwarded-host") ?? request.header("host") ?? "localhost:3000";
  const protocol = request.header("x-forwarded-proto") ?? "http";
  return `${protocol}://${host}/webhooks/trigger/${workflowId}`;
}

function buildSampleSignature(secret: string): string {
  return createHmac("sha256", secret)
    .update(JSON.stringify({ hello: "world" }))
    .digest("hex");
}

function registerWebhookUrlRoute(router: Router, config: ApiConfig): void {
  router.get(
    "/api/v1/workflows/:id/webhook-url",
    requireAuthenticatedSession,
    RequireRole(Role.ADMIN),
    asyncHandler(async (request, response) => {
      const tenantId = requireTenantId(request);
      const workflowId = readWorkflowId(request);
      const workflow = await getWorkflowById(workflowId, tenantId);

      if (!workflow || workflow.triggerType !== WorkflowTriggerType.WEBHOOK) {
        throw new ProblemDetailsError({
          detail: "Webhook workflow not found.",
          status: 404,
          title: "Not Found"
        });
      }

      response.status(200).json({
        requestId: request.context.requestId,
        sampleSignature: buildSampleSignature(
          workflow.webhookSecret ?? config.JOB_HMAC_GLOBAL_SECRET
        ),
        webhookUrl: buildWebhookUrl(request, workflow.id)
      });
    })
  );
}

function registerWorkflowEventRoute(router: Router): void {
  router.post(
    "/api/v1/workflows/events/:topic",
    requireAuthenticatedSession,
    RequireRole(Role.ADMIN),
    asyncHandler(async (request, response) => {
      const tenantId = requireTenantId(request);
      const topic = String(request.params.topic ?? "");

      emitWorkflowInternalEvent({
        payload: (request.body ?? {}) as Record<string, unknown>,
        tenantId,
        topic
      });

      response.status(202).json({
        accepted: true,
        requestId: request.context.requestId,
        topic
      });
    })
  );
}

const registerCrudWorkflowRoutes: WorkflowRouteRegistrar[] = [
  (router) => registerListWorkflowsRoute(router),
  (router, config) => registerCreateWorkflowRoute(router, config),
  (router) => registerGetWorkflowRoute(router),
  (router, config) => registerUpdateWorkflowRoute(router, config),
  (router) => registerDeleteWorkflowRoute(router)
];

const registerWorkflowExecutionRoutes: WorkflowRouteRegistrar[] = [
  (router) => registerWorkflowLineageRoute(router),
  (router, config) => registerWorkflowRevisionRoutes(router, config),
  (router, config) => registerRunWorkflowRoute(router, config)
];

const registerWorkflowEventRoutes: WorkflowRouteRegistrar[] = [
  (router, config) => registerWebhookUrlRoute(router, config),
  (router) => registerWorkflowEventRoute(router)
];

function applyWorkflowRegistrars(
  router: Router,
  config: ApiConfig,
  registrars: WorkflowRouteRegistrar[]
): void {
  for (const registerRoute of registrars) {
    registerRoute(router, config);
  }
}

export function createWorkflowsRouter(config: ApiConfig): Router {
  const router = Router();

  applyWorkflowRegistrars(router, config, registerCrudWorkflowRoutes);
  applyWorkflowRegistrars(router, config, registerWorkflowExecutionRoutes);
  applyWorkflowRegistrars(router, config, registerWorkflowEventRoutes);

  return router;
}

