void test("diagnostic mode uses the deep probe and preserves deep response mode", async () => {
  let pingDatabaseCalled = 0;
  let pingDatabaseDeepCalled = 0;

  const service = createDeepHealthService(createTestApiConfig(), {
    pingDatabase: async () => {
